head.script:
scwin.initData = {
	"isValidate" : false,
	"isSaveProcess" : false,
	"acbMappingCdObj" : {
		"elcpwstnNm" : "cmmnCd"
	},
	"acbMappingNmObj" : {
		"recEqpCdNm" : "cmmnCd"
	},
	"valInfo" : [
		{id : "elcpwstnNm", maxLength : 40, mandatory : true},
		{id : "mon01IemVu", maxByteLength : 22, number : true},
		{id : "mon02IemVu", maxByteLength : 22, number : true},
		{id : "mon03IemVu", maxByteLength : 22, number : true},
		{id : "mon04IemVu", maxByteLength : 22, number : true},
		{id : "mon05IemVu", maxByteLength : 22, number : true},
		{id : "mon06IemVu", maxByteLength : 22, number : true},
		{id : "mon07IemVu", maxByteLength : 22, number : true},
		{id : "mon08IemVu", maxByteLength : 22, number : true},
		{id : "mon09IemVu", maxByteLength : 22, number : true},
		{id : "mon10IemVu", maxByteLength : 22, number : true},
		{id : "mon11IemVu", maxByteLength : 22, number : true},
		{id : "mon12IemVu", maxByteLength : 22, number : true}
	]
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSPN5000000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("strtDt" , utilLib.getCurrentDate("yyyy"));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("setcscCd", "ALL");
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDt = dmaSearchParam.get("strtDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsElcpwstnDivCd = dmaSearchParam.get("elcpwstnCd");

	if (String(strtDt).length != 4) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

	var option = {
		action : "pn/reciss/retrieve-rec-iss.do"
			+ queryString,
		method : "get",
		resData : dltRecIssList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRow.setValue(dltRecIssList.getRowCount());
	var mandatoryList = scwin.initData.valInfo.filter(obj => obj.mandatory);
	for (var i = 0; i < dltRecIssList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdRecIssList.setCellReadOnly(i, obj.id, true);
		});
	}
	scwin.initData.isValidate = false;
};

/**
 * 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow_onclick = function() {
	var newIndex = dltRecIssList.insertRow();

	grdRecIssList.setFocusedCell(newIndex, "elcpwstnNm", true);
};

/**
 * 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow_onclick = function() {
	var rowIndexsList = grdRecIssList.getAllFocusedRowIndex();

	dltRecIssList.removeRows(rowIndexsList);
};

/**
 * 그리드뷰의 내용을 검증한다.
 * @param
 * @return
 */
scwin.btnValidate_onclick = function(confirmValue) {
	if (confirmValue == true || confirmValue == undefined) {
		if (dltRecIssList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		if (utilLib.validateGridView(grdRecIssList, scwin.initData.valInfo)) {
			var columnList = scwin.initData.valInfo.filter(obj => obj.mandatory).flatMap(obj => obj.id.replace("elcpwstnNm", "recEqpCdNm"));
			if (ecsLib.gridViewPkDuplicationCheck(grdRecIssList, dltRecIssList, columnList)) {
				// 중복 데이터가 있습니다.
				return;
			}

			if (ecsLib.validateGridViewAcb(grdRecIssList, dltAutoCondition3, scwin.initData.acbMappingCdObj, scwin.initData.acbMappingNmObj)) {
				// 해당하는 {컬럼명}이(가) 존재하지 않습니다.
				return;
			}
			scwin.initData.isValidate = true;
			if (scwin.initData.isSaveProcess) {
				scwin.initData.isSaveProcess = false;
				scwin.btnSave_onclick();
			} else {
				// 데이터 검증이 완료되었습니다.
				comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
			}
		}
	} else {
		scwin.initData.isSaveProcess = false;
	}
};

/**
 * 그리드뷰의 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	scwin.initData.isSaveProcess = false;
	if (dltRecIssList.getModifiedData() == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}

	if (scwin.initData.isValidate) {
		var addCount = 0;
		var modifyCount = 0;
		var delCount = 0;
		dltRecIssList.getModifiedJSON().forEach(obj => {
			var rowStatus = obj.rowStatus;
			switch(rowStatus) {
				case "C":
					// 추가
					addCount++;
					break;
				case "U":
					// 수정
					modifyCount++;
					break;
				case "E":
					// 삭제
					delCount++;
					break;
				default:
					break;
			}
		});
		var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
		// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
		ecsLib.saveRsn($p, `${dltRecIssList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
	} else {
		scwin.initData.isSaveProcess = true;
		// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
		return;
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	requestData.dltRecIssList = dltRecIssList.getModifiedJSON();
	var prdctnYear = dmaSearchParam.get("strtDt");
	for (var obj of requestData.dltRecIssList) {
		obj.prdctnYear = prdctnYear;
	}

	var option = {
		action : "pn/reciss/process-rec-iss.do",
		reqData : requestData,
		success : "scwin.saveConfirmSuccessCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveConfirmSuccessCallback = function(resBody) {
	comLib.alert($p, resBody.message.code_name);

	scwin.btnInqire_onclick();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	scwin.btnInqire_onclick();
};

/**
 * 데이터컬렉션의 추가/변경/삭제 시 이벤트
 * @param
 * @return
 */
scwin.dltRecIssList_ondatachange = function(info) {
	scwin.initData.isValidate = false;
};

scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");

	var queryString = `?ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-rec-cnd-setcsc.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

scwin.acbSetcsc_onviewchange = function(info) {
	var ecsSetcscDivCd = info.newValue;
	dmaSearchParam.set("setcscCd", ecsSetcscDivCd);
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");

	var queryString = `?ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;

	var option = {
		action : "zz/cmmn/retrieve-rec-cnd-setcsc.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

scwin.acbElcpwstn_onviewchange = function(info) {
	dmaSearchParam.set("elcpwstnCd", info.newValue);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnSubTitle.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 15,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	// 데이터가 없어도 탬플릿만 다운받을 수 있게 comLib.downloadExcel 말고 grdID.advancedExcelDownload 적용_231113
	options = {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		rowHeight : 40,
		useDataFormat: false,
		useStyle: true,
		hidden: 1
	}
	grdRecIssList.advancedExcelDownload(options, infoArr);
};

/**
 * 엑셀의 내용을 그리드에 업로드 한다.
 * @return
 */
scwin.btnUploadExcel_onclick = function() {
	var options = {
		type : 1,
		headerExist : 1,
		startRowIndex : 1,
		startColumnIndex : 0,
		endColumnIndex : 14,
		sheetNo : 0,
		append : 0,
		status: "C",
		useMaxByteLength : true
	};
	comLib.uploadExcel(grdRecIssList, options);
};

/**
 * 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdRecIssList_onfilereadend = function(value) {
	var dltData = dltRecIssList.getAllJSON();
	var prdctnYear = dmaSearchParam.get("strtDt");
	var dltAuto3 = dltAutoCondition3.getAllJSON();
	// set JSON
	for (var idx = 0; idx < dltData.length; idx++) {
		var elcpwstnNm = (dltAuto3.find(obj => obj.cmmnCd == dltData[idx].elcpwstnNm) || 0).cmmnCd;
		dltRecIssList.setCellData(idx, "prdctnYear", prdctnYear);
		dltRecIssList.setCellData(idx, "elcpwstnNm", elcpwstnNm);
	}
};
